export const meta = {
  name: 'art-heap-allocation-research',
  description: 'Research how ART decides moving vs non-moving space allocation',
  phases: [
    { title: 'Scope decomposition' },
    { title: 'Parallel web search (4 engines)' },
    { title: 'AOSP source verification' },
    { title: 'Adversarial claim verification' },
    { title: 'Synthesize final report' }
  ]
};

// =====================================================================
// PHASE 1: SCOPE DECOMPOSITION
// =====================================================================
phase('Scope decomposition')
log('Question: ART heap allocation policy — moving space vs non-moving space decision')
log('Decoding 5 research angles:')
log('  1. FindObject/AllocObject path in heap.cc — what code decides space?')
log('  2. RegionSpace + NonMovingSpace + ZygoteSpace + ImageSpace semantics')
log('  3. kLargeObjectThreshold, kMovingObjects flag, kIsUObject')
log('  4. Concurrent copying GC (CC) collection semantics')
log('  5. AOSP master source verification for all field/method names')

// =====================================================================
// PHASE 2: PARALLEL WEB SEARCH (4 engines, per CLAUDE.md mandate)
// =====================================================================
phase('Parallel web search (4 engines)')

const queries = [
  'ART heap object allocation moving space non-moving space kLargeObjectThreshold',
  'ART RegionSpace NonMovingSpace ZygoteSpace allocation policy AOSP',
  'ART ConcurrentCopying GC evacuation region large object heap.cc FindObject',
  'ART GC heap alloc object kind kMovingObjects class object decision',
  'Android Runtime image space zygote space object placement art/runtime/gc/heap'
]

const searchResults = await parallel(queries.map(q => () =>
  // We can't call all 4 engines from a single workflow subagent, but the
  // agents dispatched here each know to use all 4. We fan out 5 agents,
  // one per search angle; each agent runs the 4-engine protocol.
  agent(
    `You are doing one search angle for an ART (Android Runtime) heap allocation research question.

## Question
ART heap allocation policy: how does ART decide which objects go in moving space (RegionSpace) vs non-moving space (NonMovingSpace / ZygoteSpace / ImageSpace)? What is the role of kLargeObjectThreshold, kMovingObjects flag, large object handling? Where in AOSP art/runtime/gc/heap.cc / heap.h is this decided?

## Your search angle
${q}

## Mandatory protocol (per user CLAUDE.md)
1. Run ALL FOUR web search engines IN PARALLEL (one message, multiple tool calls):
   - mcp__serper__google_search
   - mcp__ddg-search__search
   - mcp__tavily__tavily_search (search_depth=advanced)
   - mcp__MiniMax__web_search
2. From results, fetch top 3-5 URLs with WebFetch / mcp__fetch__imageFetch / mcp__ddg-search__fetch_content
3. Then fetch AOSP master source for any field/method/constant you cite:
   - https://android.googlesource.com/platform/art/+/master/runtime/gc/heap.cc
   - https://android.googlesource.com/platform/art/+/master/runtime/gc/heap.h
   - https://android.googlesource.com/platform/art/+/master/runtime/gc/space.h
   - https://android.googlesource.com/platform/art/+/master/runtime/gc/allocator/region_space.h
   - https://cs.android.com/android/platform/superproject/+/master:art/runtime/gc/heap.cc
   - https://cs.android.com/android/platform/superproject/+/master:art/runtime/gc/allocator/region_space.cc
4. Extract falsifiable claims with their source URLs.

## Return format (must be JSON)
{
  "angle": "<which of the 5 angles>",
  "claims": [
    {
      "claim": "<single falsifiable claim>",
      "confidence": "high|medium|low",
      "sources": [
        {"url": "...", "kind": "aosp-source|blog|doc|stackoverflow"}
      ],
      "aosp_path": "<if verified against AOSP, the path>",
      "evidence_quote": "<1-2 line quote supporting claim>"
    }
  ],
  "conflicts": ["<contradictions between sources>"],
  "followups": ["<questions for next angle or verifier>"]
}

Be precise. Do NOT invent method names or field names. If you can't verify, mark confidence=low.`,
    {label: `angle: ${q.slice(0, 40)}`, phase: 'Parallel web search (4 engines)', agentType: 'general-purpose'}
  )
))

// =====================================================================
// PHASE 3: AOSP DIRECT SOURCE VERIFICATION
// =====================================================================
phase('AOSP source verification')
const aospVerify = await agent(
`You are verifying ART heap allocation claims against AOSP master source code.

## Context
The prior web search phase produced these candidate claims (see inputs). Your job is to
fetch the ACTUAL AOSP master source and confirm or refute each one.

## Files to fetch (use mcp__fetch__imageFetch or WebFetch)
1. https://android.googlesource.com/platform/art/+/master/runtime/gc/heap.cc
   - look for: Heap::FindObject, Heap::AllocObject, Heap::IsMovingObject,
     Heap::kIsImageObjectClass, Heap::ShouldAllocLargeObject, GetDefaultSpaceForObject
2. https://android.googlesource.com/platform/art/+/master/runtime/gc/heap.h
   - look for: kDefault... , AllocSpace enum, large object threshold constants
3. https://android.googlesource.com/platform/art/+/master/runtime/gc/space.h
   - look for: Space subclasses, IsDlMallocSpace, IsRegionSpace
4. https://android.googlesource.com/platform/art/+/master/runtime/gc/allocator/region_space.h
   - look for: RegionSpace, Region, kRegionSize
5. https://cs.android.com/android/platform/superproject/+/master:art/runtime/gc/heap.cc
6. https://cs.android.com/android/platform/superproject/+/master:art/runtime/gc/allocator/region_space.cc

## Inputs
${JSON.stringify(searchResults, null, 2).slice(0, 24000)}

## What to extract
For each candidate claim, give a verdict:
- CONFIRMED: cite exact AOSP file + line range + the actual code snippet
- REFUTED: show the actual code that says otherwise
- UNVERIFIED: couldn't find, mark as low confidence

## Special focus areas
1. The exact decision tree in Heap::AllocObject or Heap::FindObject that picks space
2. The large object threshold constant name and value range
3. Image / Zygote space object kinds
4. CC (ConcurrentCopying) collector's evacuation region behavior
5. The kMovingObjects ObjectAllocatorType enumeration

## Return
{
  "verdicts": [
    {
      "original_claim": "...",
      "verdict": "CONFIRMED|REFUTED|UNVERIFIED",
      "aosp_evidence": "<file:line + code snippet>",
      "corrected_claim": "<if refuted, the corrected version>"
    }
  ],
  "additional_findings": ["<new facts surfaced from AOSP source that weren't in web search>"],
  "raw_url_coverage": ["<which AOSP URLs successfully fetched>"]
}`,
  {label: 'AOSP source verifier', phase: 'AOSP source verification', agentType: 'general-purpose'}
)

// =====================================================================
// PHASE 4: ADVERSARIAL VERIFICATION (3-vote per claim)
// =====================================================================
phase('Adversarial claim verification')
const verifiedClaims = aospVerify?.verdicts || []
const claimsToChallenge = verifiedClaims.length > 0 ? verifiedClaims : [
  { original_claim: 'ART places large objects (>kLargeObjectThreshold bytes) in non-moving space (LOS)' },
  { original_claim: 'RegionSpace is the moving space used by ConcurrentCopying GC' },
  { original_claim: 'Image and Zygote spaces are non-moving' }
]

const adversarial = await parallel(claimsToChallenge.map(c => () =>
  parallel([
    () => agent(
      `Try to REFUTE this claim about ART heap allocation. Default to refuted=true if uncertain.

Claim: ${JSON.stringify(c)}

Look at AOSP master:
- art/runtime/gc/heap.cc — FindObject, AllocObject, AllocLargeObject
- art/runtime/gc/heap.h
- art/runtime/gc/space.h
- art/runtime/gc/allocator/region_space.h
- art/runtime/gc/allocator/dlmalloc_space.h
- art/image_space.h

Use these search engines in parallel (4-engine protocol):
- mcp__serper__google_search
- mcp__ddg-search__search
- mcp__tavily__tavily_search (search_depth=advanced)
- mcp__MiniMax__web_search

Then fetch AOSP source. Return JSON: {"refuted": true|false, "reason": "...", "evidence_url": "..."}`,
      {label: `refute: ${(c.original_claim || '?').slice(0, 30)}`, phase: 'Adversarial claim verification', agentType: 'general-purpose'}
    ),
    () => agent(
      `Try to CONFIRM this claim about ART heap allocation. Be skeptical and demand strong evidence.

Claim: ${JSON.stringify(c)}

Search engines (parallel, 4 engines per CLAUDE.md):
- mcp__serper__google_search
- mcp__ddg-search__search
- mcp__tavily__tavily_search (search_depth=advanced)
- mcp__MiniMax__web_search

Then fetch AOSP master source. Return JSON: {"confirmed": true|false, "reason": "...", "aosp_evidence": "file:line + snippet", "confidence": "high|medium|low"}`,
      {label: `confirm: ${(c.original_claim || '?').slice(0, 30)}`, phase: 'Adversarial claim verification', agentType: 'general-purpose'}
    ),
    () => agent(
      `Independent third perspective on this ART heap allocation claim. Treat as a tie-breaker.

Claim: ${JSON.stringify(c)}

Briefly:
1. Is the claim about ALL ART versions, or specific to G1 (CC GC) or another collector?
2. Is "moving space" == RegionSpace in current AOSP master?
3. What about the fallback ZygoteSpace / ImageSpace in pre-compilation boot?

Use 4 search engines in parallel, then AOSP source. Return JSON: {"verdict": "true|false|partial", "explanation": "...", "scope_note": "<version/collector caveats>"}`,
      {label: `tiebreak: ${(c.original_claim || '?').slice(0, 30)}`, phase: 'Adversarial claim verification', agentType: 'general-purpose'}
    )
  ]).then(votes => ({
    claim: c,
    refute_vote: votes[0]?.refuted ? 'refute' : 'confirm',
    confirm_vote: votes[1]?.confirmed ? 'confirm' : 'refute',
    tiebreak_vote: votes[2]?.verdict || 'unknown',
    confidence: votes[1]?.confidence || 'low',
    notes: votes.map(v => v?.reason || v?.explanation).filter(Boolean)
  }))
))

// Tally: 2-of-3 refutes → kill, 2-of-3 confirms → keep
const finalClaims = adversarial.map(v => {
  const refutes = [v.refute_vote, v.confirm_vote, v.tiebreak_vote].filter(x => x === 'refute').length
  const confirms = [v.refute_vote, v.confirm_vote, v.tiebreak_vote].filter(x => x === 'confirm').length
  const survived = confirms >= 2
  return {
    claim: v.claim.original_claim,
    survived,
    confidence: v.confidence,
    notes: v.notes
  }
})

// =====================================================================
// PHASE 5: SYNTHESIZE
// =====================================================================
phase('Synthesize final report')
return {
  question: 'ART heap allocation: how are objects split between moving (RegionSpace) and non-moving space?',
  search_angles: queries,
  search_results_count: searchResults.filter(Boolean).length,
  aosp_verdicts: aospVerify,
  adversarial_results: finalClaims,
  additional_findings: aospVerify?.additional_findings || [],
  next_steps: 'Format as final answer with [知识来源: ...] tags, confidence labels, and AOSP path:line citations per CLAUDE.md output format.'
}

