    static constexpr int SHOW_STATIC = 1 << 2;
    static constexpr int SHOW_FIELD = 1 << 3;
    static constexpr int SHOW_ALL = SHOW_METHOD | SHOW_IMPL |
                                    SHOW_STATIC | SHOW_FIELD;

    ClassCommand() : Command("class") {}
